import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { PRODUCTS } from './data';
import { useCart } from './CartContext';

const SORT_OPTIONS = [
  { label: 'Newest First', value: 'newest' },
  { label: 'Price: Low to High', value: 'price_asc' },
  { label: 'Price: High to Low', value: 'price_desc' },
  { label: 'Most Popular', value: 'popular' },
];

const PRICE_RANGES = {
  'Under ₹500': p => p.price < 500,
  '₹500 – ₹1,000': p => p.price >= 500 && p.price <= 1000,
  '₹1,000 – ₹2,500': p => p.price > 1000 && p.price <= 2500,
  '₹2,500+': p => p.price > 2500,
};

const NAV_FILTERS = {
  'New Arrivals': p => p.badge === 'New',
  'Best Sellers': p => p.badge === 'Hot',
  'Anime': p => !['Harry Potter', 'Marvel', 'DC Comics', 'Star Wars', 'Game of Thrones', 'The Boys', 'Gundam', 'Evangelion', 'Transformers'].includes(p.series),
  'Western': p => ['Harry Potter', 'Marvel', 'DC Comics', 'Star Wars', 'Game of Thrones', 'The Boys'].includes(p.series),
  'Collectibles': p => true,
  'Sale 🔥': p => p.oldPrice != null,
};

export default function CategoryPage() {
  const { series } = useParams();
  const navigate = useNavigate();
  const { addToCart } = useCart();

  const [sort, setSort] = useState('newest');
  const [addedId, setAddedId] = useState(null);

  // Figure out what kind of filter this is
  const isPriceRange = Object.keys(PRICE_RANGES).includes(series);
  const isNavFilter = Object.keys(NAV_FILTERS).includes(series);

  let products = PRODUCTS;

  if (isPriceRange) {
    products = PRODUCTS.filter(PRICE_RANGES[series]);
  } else if (isNavFilter) {
    products = PRODUCTS.filter(NAV_FILTERS[series]);
  } else if (series === 'All Anime') {
    products = PRODUCTS;
  } else {
    // Filter by series name
    products = PRODUCTS.filter(p => p.series === series);
  }

  // Sort
  if (sort === 'price_asc') products = [...products].sort((a, b) => a.price - b.price);
  if (sort === 'price_desc') products = [...products].sort((a, b) => b.price - a.price);

  const handleAdd = (e, product) => {
    e.stopPropagation();
    addToCart(product);
    setAddedId(product.id);
    setTimeout(() => setAddedId(null), 1400);
  };

  // Nice title for price ranges and nav filters
  const pageTitle = series;

  return (
    <div className="min-h-screen bg-white">

      {/* Breadcrumb */}
      <div className="px-6 py-3 border-b border-gray-100 text-xs text-gray-400 flex items-center gap-2">
        <button onClick={() => navigate('/')} className="hover:text-ink transition-colors">Home</button>
        <span>›</span>
        <span className="text-ink font-medium">{pageTitle}</span>
      </div>

      {/* Header */}
      <div className="px-6 py-6 border-b border-gray-100">
        <div className="flex items-center justify-between flex-wrap gap-4">
          <div>
            <h1 className="text-2xl font-bold text-ink" style={{ fontFamily: 'Playfair Display, serif' }}>
              {pageTitle}
            </h1>
            <p className="text-sm text-gray-400 mt-1">
              {products.length} {products.length === 1 ? 'product' : 'products'} found
            </p>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-xs text-gray-400 font-medium">Sort by:</span>
            <select
              value={sort}
              onChange={e => setSort(e.target.value)}
              className="text-sm border border-gray-200 rounded-lg px-3 py-2 outline-none focus:border-ink transition-colors bg-white text-ink"
            >
              {SORT_OPTIONS.map(o => (
                <option key={o.value} value={o.value}>{o.label}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Products */}
      <div className="px-6 py-6">
        {products.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-24 text-center">
            <div className="text-6xl mb-4">🔍</div>
            <h3 className="text-lg font-bold text-ink mb-2">No products found</h3>
            <p className="text-sm text-gray-400 mb-6">
              Nothing here yet for <strong>{pageTitle}</strong>. Check back soon!
            </p>
            <button
              onClick={() => navigate('/')}
              className="bg-ink text-white px-6 py-2.5 rounded-lg text-sm font-semibold hover:bg-gray-800 transition-colors"
            >
              Back to Home
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-5">
            {products.map(product => {
              const discount = product.oldPrice
                ? Math.round((1 - product.price / product.oldPrice) * 100)
                : null;
              return (
                <div
                  key={product.id}
                  onClick={() => navigate(`/product/${product.id}`)}
                  className="group cursor-pointer"
                >
                  <div className="relative rounded-xl overflow-hidden bg-gray-100 mb-3" style={{ aspectRatio: '0.78' }}>
                    <img
                      src={product.img}
                      alt={product.name}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                      loading="lazy"
                    />
                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-all duration-300 rounded-xl" />
                    {product.badge && (
                      <span className={`absolute top-3 left-3 text-[10px] font-bold px-2.5 py-1 rounded-full ${product.badgeColor}`}>
                        {product.badge}
                      </span>
                    )}
                    <button
                      onClick={(e) => handleAdd(e, product)}
                      className={`
                        absolute bottom-3 left-3 right-3 text-xs font-bold tracking-wide py-2.5 rounded-lg border-none
                        transition-all duration-200
                        ${addedId === product.id
                          ? 'opacity-100 translate-y-0 bg-green-600 text-white'
                          : 'opacity-0 group-hover:opacity-100 translate-y-2 group-hover:translate-y-0 bg-white/95 text-ink hover:bg-ink hover:text-white'
                        }
                      `}
                    >
                      {addedId === product.id ? '✓ Added!' : '+ Add to Bag'}
                    </button>
                  </div>
                  <div className="text-[10px] font-bold tracking-[2px] uppercase text-gray-400 mb-1">{product.series}</div>
                  <div className="text-sm font-semibold text-ink mb-2 leading-snug">{product.name}</div>
                  <div className="flex items-center gap-2">
                    <span className="text-base font-bold text-ink">₹{product.price.toLocaleString('en-IN')}</span>
                    {product.oldPrice && (
                      <>
                        <span className="text-xs text-gray-400 line-through">₹{product.oldPrice.toLocaleString('en-IN')}</span>
                        <span className="text-xs font-semibold text-green-600">{discount}% off</span>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
